// /frontend/src/components/Forecast.jsx
import React from "react";
const toF = (c) => (c == null ? null : (c * 9) / 5 + 32);
const round = (x) => (x == null ? null : Math.round(x));

export default function Forecast({ hourly = [], daily = [], daily16 = [], unit = "metric" }) {
  const fmt = (c) => (unit === "imperial" ? round(toF(c)) : round(c));

  const hasDaily = Array.isArray(daily) && daily.length > 0;
  const hasExt = Array.isArray(daily16) && daily16.length > 0;

  return (
    <div className="space-y-6">
      {/* Hourly */}
      <section>
        <h2 className="text-lg font-semibold mb-2">Next Hours</h2>
        <div className="flex gap-3 overflow-x-auto pb-2">
          {(hourly ?? []).map((h) => (
            <div key={h.dt} className="shrink-0 rounded-2xl px-3 py-2 bg-black/40 backdrop-blur">
              <div className="text-sm">
                {new Date((h.dt ?? Date.now()/1000) * 1000).toLocaleTimeString([], { hour: "numeric" })}
              </div>
              <div className="text-center text-2xl">{fmt(h.temp)}°</div>
              <div className="text-xs opacity-75">{Math.round((h.pop ?? 0) * 100)}% rain</div>
            </div>
          ))}
          {!hourly?.length && <div className="opacity-70 text-sm">No hourly data.</div>}
        </div>
      </section>

      {/* Daily (7–10 days, whatever backend returns) */}
      <section>
        <h2 className="text-lg font-semibold mb-2">Daily</h2>
        <div className="flex flex-col gap-2">
          {hasDaily ? daily.map((d) => (
            <div key={d.dt} className="w-full rounded-2xl px-4 py-3 bg-black/40 backdrop-blur flex items-center justify-between">
              <div className="w-28">
                {new Date((d.dt ?? Date.now()/1000) * 1000).toLocaleDateString(undefined, { weekday: "short" })}
              </div>
              <div className="flex-1 text-right">{fmt(d.min)}° / <strong>{fmt(d.max)}°</strong></div>
              <div className="w-20 text-right text-sm opacity-75">{Math.round((d.pop ?? 0) * 100)}%</div>
            </div>
          )) : <div className="opacity-70 text-sm">No daily data.</div>}
        </div>
      </section>

      {/* Extended (16‑day if available) */}
      <section>
        <h2 className="text-lg font-semibold mb-2">16‑Day Forecast</h2>
        <div className="flex flex-col gap-2">
          {hasExt ? daily16.map((d, i) => (
            <div key={`${d.dt}-${i}`} className="w-full rounded-2xl px-4 py-3 bg-black/40 backdrop-blur flex items-center justify-between">
              <div className="w-28">
                {new Date((d.dt ?? Date.now()/1000) * 1000).toLocaleDateString(undefined, { weekday: "short" })}
              </div>
              <div className="flex-1 text-right">{fmt(d?.temp?.min ?? d.min)}° / <strong>{fmt(d?.temp?.max ?? d.max)}°</strong></div>
              <div className="w-20 text-right text-sm opacity-75">{Math.round((d.pop ?? 0) * 100)}%</div>
            </div>
          )) : <div className="opacity-70 text-sm">No extended forecast available.</div>}
        </div>
      </section>
    </div>
  );
}
